('680279fde3c98b0941765843', '实名表彰客房部的janice 许小姐.', '["https://dimg04.c-ctrip.com/images/0230612000ihq9nrl91C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000ihr19z8EA2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000ihqhkn98541_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000ihr731n7211_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000ihqvew6B182_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000ihqpja99410_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-13', '花园大床房', '大床房', '家庭亲子', 19, 0, 19, 3, '["客房服务"]'::jsonb, '客房服务', NULL, NULL),
('680279fde3c98b0941765844', '酒店大堂很漂亮，服务态度也很好，家庭出游不错的选择！', '["https://dimg04.c-ctrip.com/images/0231a12000i4ergol8215_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000i4ejjzr7304_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000i4efgqzF771_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-28', '花园双床房', '双床房', '家庭亲子', 26, 0, 14, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680279fde3c98b0941765845', '这次入住花园酒店是为了庆祝女朋友生日
非常感谢广州花园酒店给了我们这么美好的周末
广州花园酒店虽然已经有接近40年的历史了
但是房间，酒店设施，设计风格
一点都看不出老旧的感觉
——————分割线——————
我们买的是酒店1088的套餐
包含双早+大床房+双人自助茶市（夜晚）
星期六晚上办理入住的时候
可能是晚上比较多人入住
酒店临时加开了办入住的工作人员
仅用十分钟就拿到房卡
因为是庆祝生日，我提前几天就打电话给酒店
想说布置一下房间，结果一打开房门真的很惊喜
（在此感谢当时接电话，帮我安排的总机小黄）
到了荔湾亭，接待我们的男经理（穿黑色衣服）
很热情！还知道是庆祝生日，提出送了两份主食
（点赞????但不记得他的工牌了）
第二天早餐～～
是我吃过最丰盛的酒店早餐之一了
比珠江新城的一些奢侈酒店还丰盛
带我们入坐的是MONEY（好像是这个名字）
是一位外籍人士，但是普通话超级好！
总的来说再次很感谢花园酒店给我们这么好的回忆
不仅给我女朋友一个美好的生日
更为我们洗去一周的班味～～', '["https://dimg04.c-ctrip.com/images/0234o12000gujl10a780D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000gujm6zcB5A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000gujansl9D28_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000gujl186161D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-24', '花园大床房', '大床房', '情侣出游', 450, 0, 6, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027a0ae3c98b0941765846', '客房不错，细节服务挺好。大堂李文和小何服务很好', '["https://dimg04.c-ctrip.com/images/0235z12000jfvi0hz1592_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000jfvrxge3C08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000jfw58l88C9A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-31', '花园双床房', '双床房', '朋友出游', 23, 0, 4, 5, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027a0ae3c98b0941765847', '来之前比较了很多家，还是挑选了这家底蕴深厚的老牌五星，卫生、设施、管理和服务都有品质保证：
房间整洁宽敞，装修材质好品牌好，床品舒适，遇到的每一位酒店员工都如春风般和煦，前台小姐姐、客房部的小天和他的同事们，积极主动帮助沟通解决遇到的问题，特别暖心。
酒店门口即地铁，自有花园很棒，健身房壁球室俱全，屋顶游泳池两个大泡池很舒适，早餐有三个餐厅选择，各有特色，相当不错！周边可选餐厅很多，白云酒店白云轩，广州酒家，点都德……

非要说一下缺点的话，就是：1、自助早餐食物还可以丰富和提高品质；2、大堂小姐姐的亮闪闪迎宾服不知道是不是岭南风，总觉得有点不搭环境，好在小姐姐们服务还是贴心周到的；3、热忱的门童服务挺加分的，可是能不要安排纤弱的小姐姐吗？门比人都要重了，看着好让人心疼，酒店也要懂得怜香惜玉，哈哈
下次再来广州的首选，还会带家人来小住。', '["https://dimg04.c-ctrip.com/images/0235412000g1mij1p70FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000g1md76t9939_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000g1miyxx6801_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000g1mgkn8520F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000g1mc8qn89BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000g1md8fnEC3E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000g1mdss197A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000g1o8vsc84F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园大床房', '大床房', '其他', 373, 0, 18, 9, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('68027a0ae3c98b0941765849', '入住虽有波折，但先抑后扬，最后感受完美！', '["https://dimg04.c-ctrip.com/images/0231c12000ircho6xF92B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000irf02jkAE54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000ireg4gt8F49_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-26', '花园大床房', '大床房', '家庭亲子', 20, 0, 3, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a0ae3c98b094176584a', '前台小姐姐ann，Betty，rain，ZARA，mancy，Rebecca，YOLO，Gillian，Kasas，温顺可爱、聪明伶俐、勤奋好学、认真刻苦、性格开朗，沉鱼落雁 、闭月羞花、国色天香、婀娜多姿、端庄秀丽、貌美如花、房间也特别好，感觉进了皇宫一样！', '["https://dimg04.c-ctrip.com/images/0236w12000fquvw5u1B9D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231p12000fquz7utDF11_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-25', '花园大床房', '大床房', '朋友出游', 130, 0, 1, 4, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027a0ae3c98b094176584b', '服务热情周到细致！下午茶糕点新鲜可口??', '["https://dimg04.c-ctrip.com/images/0234a12000ie8mzr00CE7_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-08', '红棉双床套房', '套房', '家庭亲子', 20, 0, 14, 4, '["前台服务","餐饮设施"]'::jsonb, '前台服务', '餐饮设施', NULL),
('68027a0ae3c98b094176584c', '非常非常赞 虽然有年头了 但是还是有气派 餐饮服务很好 不管是早餐还是行政酒廊 房间格局很好 酒店的花园实在太好看了', '["https://dimg04.c-ctrip.com/images/0231h12000hzw6egw8E86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000hzx61gp7140_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000hzx0n9aAB65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000hzv3ql6D7FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000hzw49ed7927_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000hzwxg51DD5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-23', '花园双床房', '双床房', '家庭亲子', 58, 0, 18, 7, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('68027a0ae3c98b094176584d', '酒店就是一座博物馆，这诺大的博物馆典藏的旧物，一桩一件都值得驻足细品，第二次来才把这家开业快40年的白金酒店的内涵充分发掘，是历史的见证，是时光的沉淀，更是中国文化的伟大传承?????? 
服务来说，整个酒店的服务人员整体还是非常有礼貌和服务态度的，感谢客房部Tia赠送的中秋月饼。
重点说说在酒店的三天都在30层行政酒廊的360°旋转餐厅用餐，被Carrie 的服务一整个感动到，为了中秋节三天我们有最好的体验主动提供了很多升级和附加服务，还有另外几位Echo、Kelly 等小姐姐和早餐的小哥哥都态度亲切，服务殷勤，让整个节日的体验充满温情
所以，
爱才是人生的行囊，
其余都是包袱[太阳]', '["https://dimg04.c-ctrip.com/images/0233512000flttqmmE248_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000fltjht6E0B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000flty1y452A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000fltxk3sB30E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000flu1oil68E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000flu5qmmF22D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000fltle781C39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000fltle7aAEE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000fltlxvp225C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 297, 0, 11, 9, '["整体满意度","餐饮设施","客房服务"]'::jsonb, '整体满意度', '餐饮设施', '客房服务'),
('68027a0ae3c98b094176584e', '广州花园酒店地位位置不错，处于越秀区，然后酒店文化底蕴深厚，四楼居然还有博物馆，这让我十成分惊讶，然后就是我很喜欢这里的行政酒廊，不知道为什么它要搬下来这里的一楼，我觉得这里远不如30 楼的环境，但是这也怪不得这些服务的小姐姐，而且beryle，echo，她们还是很热情的特别是beryle她热情介绍这里，并且有什么吃喝等，很热情的服务，很喜欢她们，但是还是喜欢三十楼，在楼上的安静环境舒适，而且这次再次来是寻找以前来过的餐厅', '["https://dimg04.c-ctrip.com/images/0234g12000frjjx5t2B32_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233r12000frjjbjeB3B6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236w12000frjiyeiE796_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-26', '花园双床房', '双床房', '其他', 213, 0, 1, 8, '["公共设施","前台服务","安静程度"]'::jsonb, '公共设施', '前台服务', '安静程度'),
('68027a0ae3c98b094176584f', '环境不错90年代的CBD，现在也不过时。酒店性价比高，服务热情，因老人怕冷，服务员还送一台热风机，服务很到位。', '["https://dimg04.c-ctrip.com/images/0230d12000hg4gzbz1541_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-27', '花园大床房', '大床房', '家庭亲子', 55, 0, 6, 8, '["性价比","客房服务","整体满意度"]'::jsonb, '性价比', '客房服务', '整体满意度'),
('68027a15e3c98b0941765850', '广州花园酒店地理位置优越，交通便利，大堂也是非常的富丽堂皇，不愧是白金五星级酒店，尤其要点名表扬行政酒廊的Echo，Cathy，kanchan，她们服务十分到位,行政酒廊从三十楼搬下来到一楼的酒吧里面了，虽然样子变了，但是她们服务还是如往常一样，服务周到，这让我感到非常满意??
为这个酒店有你们这样的好员工点赞', '["https://dimg04.c-ctrip.com/images/0233e12000fot0x4k5671_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000fot14suE5F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000fosx0ixF989_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000fot0qbj86A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000fot2t1mDA6F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-22', '花园双床房', '双床房', '商务出差', 156, 0, 1, 8, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027a15e3c98b0941765851', '来广州转机住了一晚 酒店装饰很大气 地理位置也不错 附近有不少吃的', '["https://dimg04.c-ctrip.com/images/0235o324x8z5dxqwm79EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d324x8z51ufnuA8F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p324x8z5e7vxn6156_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '花园大床房', '大床房', '独自旅行', 33, 0, 6, 5, '["交通便利性","周边配套"]'::jsonb, '交通便利性', '周边配套', NULL),
('68027a15e3c98b0941765852', '房间比较小 但地理位置和整体环境和服务不错', '["https://dimg04.c-ctrip.com/images/0235q12000i8ecw0dE26F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000i8ewsot623B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-02-01', '花园大床房', '大床房', '家庭亲子', 21, 0, 13, 5, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027a15e3c98b0941765853', '广州花园酒店入住体验令人满意，房间布置温馨，空间宽敞，床铺舒适，地理位置优越，交通便利，周边配套设施完善。工作人员热情好客，服务周到，让人有宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0233m12000gf9imix1611_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000gf9cqyj0EC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000gfadrj1F969_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-01', '花园双床房', '双床房', '情侣出游', 78, 0, 3, 8, '["整体满意度","房间设施","交通便利性"]'::jsonb, '整体满意度', '房间设施', '交通便利性'),
('68027a15e3c98b0941765854', '广州花园酒店的入住体验堪称完美，从踏入酒店的那一刻起就感受到了无微不至的尊贵服务！行政酒廊的Jennifer、Cathy和Louis三位工作人员尤为令人印象深刻。客务中心的小琳更是全程暖心护航，无论是行程建议还是突发需求，她总能迅速响应并完美解决。酒店设施高端典雅，窗外城市景观令人沉醉，行政酒廊的精致餐点与静谧氛围更是加分项。这次入住不仅享受了奢华的硬件，更被充满人情味的服务深深打动，绝对是我在广州的首选下榻之地！', '["https://dimg04.c-ctrip.com/images/0233112000jfb07m63599_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000jfb1vk59EA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000jf9qftiB755_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-30', '红棉大床套房', '套房', '情侣出游', 209, 0, 48, 9, '["前台服务","整体满意度","景观/朝向"]'::jsonb, '前台服务', '整体满意度', '景观/朝向'),
('68027a15e3c98b0941765855', '房间超级喜欢，环境很好，位置在友谊商店对面，很多外国人，服务一流，前台小姐姐帮我们升级了套房，还送了欢迎甜品，以后还会入住。', '["https://dimg04.c-ctrip.com/images/0233712000gojb1dz18B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000goips2aE9CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000gojc6apE6A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000goja4ku6FA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000gohw4dgAF2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000gojeju9F0ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000gohsdmc9AE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000goirueqCA94_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-14', '城央绿意双床房', '双床房', '家庭亲子', 62, 0, 2, 8, '["前台服务","整体满意度","周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套'),
('68027a15e3c98b0941765856', '房间宽敞明亮，服务热情周到，环境优美舒适，停车方便，出行便捷，下次一定还在住。', '["https://dimg04.c-ctrip.com/images/0236c12000hge8ufe3F87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000hgefb6vF0C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000hge36s2B573_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000hgeeecm80F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000hgefeti9609_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-28', '花园大床房', '大床房', '商务出差', 39, 0, 53, 5, '["整体满意度","交通便利性","公共设施"]'::jsonb, '整体满意度', '交通便利性', '公共设施'),
('68027a15e3c98b0941765857', '设施：非常完善
卫生：干净整洁
环境：优美舒适宜人
服务：态度非常好??四楼博物馆今天开放推荐了朋友带儿子去参观了，真幸运因为平时周一是不开放的，刚好碰上国庆假期哈哈。', '["https://dimg04.c-ctrip.com/images/0230m12000fv4d0th4DBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000fv3zdteB025_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000fv4pumwA817_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000fv498g8F8A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000fv3jwuz4159_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000fv3pma66D97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000fv3jwv1E189_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000fv3e76sC999_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000fv4aerpB89E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-30', '花园双床房', '双床房', '朋友出游', 84, 0, 21, 8, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027a15e3c98b0941765858', '尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:多谢当日服务员echo,Carrie,Kitty 的亲切服务，服务很周到，而且时不时的会问我们有没有需要帮助的??食物出品很好，配得上五星级的头衔！', '["https://dimg04.c-ctrip.com/images/0236f12000frw3qsw8019_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000frvht0sFDD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000frw6d5v67C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000frwaxdd1E17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000frw452k6B86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000frw243056E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000frwedpmF278_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000frvvyo03340_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000frw5gggF176_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-26', '花园双床房', '双床房', '家庭亲子', 105, 0, 5, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a15e3c98b0941765859', '携程的三天两晚套票，中秋假期的尾巴过来广州老派酒店放空身心，一天好好待在酒店享乐就好，除了包早餐，还包含了下午茶，欢乐时光在30楼的行政礼遇，行政酒廊的Carrie、Echo、Kitty服务周到，让这次行程倍感亲切！', '["https://dimg04.c-ctrip.com/images/0230912000fn3bbpa8C50_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235q12000fn3a82a58E8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232q12000fn378y1B695_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232l12000fn3auy2013F_R_150_150_R5_Q70_D.png"]'::jsonb, 3.5, 3, '2024-09-19', '花园双床房', '双床房', '家庭亲子', 108, 0, 2, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a1fe3c98b094176585a', '春节期间和家人去广州旅游，入住广州越秀区花园酒店。这是一家老牌5星酒店，可以看到当年的金碧辉煌，大堂背景墙是金色的，登记的前台还得排长队。可以看得出大家对花园酒店的认可。早餐丰富，服务热情周到。后花园太漂亮了。特别提出表扬的是前台mancy（黄女士），看到我们带了孩子，主动为我们升级了房间，非常感谢！给酒店全5星好评，下次来广州一定再住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234612000iaqkfawC09B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000iaqz0854BAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000iaqy0f283AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 174, 0, 4, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027a1fe3c98b094176585b', '非常棒的酒店，从一进酒店就感觉到非常温馨热情，办理入住的前台服务员Yolo耐心细心，还有负责酒店讲解的小李，讲解的很细致。特别感谢酒店给做的房间布置并升级房型，使我们度过了一个快乐假期。谢谢。', '["https://dimg04.c-ctrip.com/images/0230212000fq4c4cg0256_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000fq4hkc04391_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000fq47rfc2BC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000fq49cdg7978_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000fq4gxurFA66_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000fq4xutxBDFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000fq4j8luBB84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000fq4t2nhE04F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000fq4sujt7B37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-24', '花园双床房', '双床房', '家庭亲子', 96, 0, 114, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027a1fe3c98b094176585c', '酒店地理位置很好，设施豪华而大气；服务很贴心，过生日还送蛋糕??，不愧是老牌五星酒店。下次来还会入住。', '["https://dimg04.c-ctrip.com/images/0235r12000h0xpim0799E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000h0yjz0n8C4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000h0xq4bu00D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000h0yyt9i166C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000h0z2a81EE84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000h0yppp16D6C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-04', '红棉双床套房', '套房', '家庭亲子', 51, 0, 4, 7, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027a1fe3c98b094176585d', '总体满意，很有底蕴的五星白金酒店，客房服务非常好，餐饮味道不错，唯一提点小意见，就是行政酒廊环境小，酒水可选择少，餐食精致）（这点很喜欢），当我提出能否提供一碗白米饭，服务员的回答是，我们这里的欢乐时光就是这样，没有白米饭提供，我觉得这样的回答不应该是五星酒店的回答，本人因为特别喜欢行政酒廊，去过很多五星酒店的行政酒廊，所以这种回答让我觉得挺惊讶的，这是这次住店的真实感受，有时间我还是会再去入住的', '["https://dimg04.c-ctrip.com/images/0232v12000fmwdxwwD3DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000fmwbj4c7DC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000fmwdgb03CF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000fmwq3lbE26D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-09-19', '花园双床房', '双床房', '其他', 200, 1, 11, 8, '["餐饮设施","客房服务","整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度'),
('68027a1fe3c98b094176585e', '酒店环境优雅，近市中心交通十分便捷。－流的服务水平，有宾至如归的感觉。早餐十分丰盛味道好极了。如有机会，下次再入住。', '["https://dimg04.c-ctrip.com/images/0233z12000gryol737A20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000gry5gt4B73A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000grycju82E20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-11-20', '花园双床房', '双床房', '家庭亲子', 58, 0, 3, 6, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027a1fe3c98b094176585f', '订的基础房型，前台小哥给我升级了套房，非常惊喜，物超所值。酒店离淘金火车站也非常近，出行方便。酒店四楼还有个博物馆，介绍广州酒店发展历史，值得一看。推荐大家来广州住花园酒店。', '["https://dimg04.c-ctrip.com/images/0237112000fzoghsqC67C_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233k12000fzog8c23130_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230u12000fzoekeu45B8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234312000fzofufb2208_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234q12000fzoevep9247_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235b12000fzoe4ek96DC_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231h12000fzof4yiE716_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-10-05', '花园大床房', '大床房', '情侣出游', 87, 0, 4, 8, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('68027a1fe3c98b0941765860', '在携程囤的行政礼遇三天两晚套餐，趁着中秋假期来广州老牌五星酒店放松一下。套餐包含酒店30楼行政酒廊早餐、下午茶和Happy hour，懒得出门的话可以一天三餐都在酒店解决了。早餐还会开放旋转餐厅区域。酒店还送了跟广东省博物馆联名的月饼。行政酒廊的Carrie、Echo服务热情周到，让这次行程倍感亲切！', '["https://dimg04.c-ctrip.com/images/0233j12000fntxnkjD9A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000fnub0ct53AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000fntvnoq66BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000fntwzzc4653_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000fnu6mzzE84C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000fntpqmwB833_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000fnuc2wz718B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000fnua80i077D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000fntmr789B18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-20', '花园双床房', '双床房', '家庭亲子', 151, 0, 5, 9, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a1fe3c98b0941765861', '30年前爸爸妈妈蜜月时候来过的酒店
这次打卡很有纪念意义啦
非常感谢酒店准备的浪漫惊喜
	
